export class NoopAlgorithm extends AbstractAlgorithm {
  constructor({ ...options }: AlgorithmOptions) {
    super(options);
  }
  public calculate({
    markers,
    map,
    mapCanvasProjection,
  }: AlgorithmInput): AlgorithmOutput {
    return {
      clusters: this.cluster({ markers, map, mapCanvasProjection }),
